// epoch_topics.cc:175-214 (simplified)
std::optional<Topic> EpochTopics::TopicForSiteForDisplay(...) {
  // Select the real topic for this epoch
  Topic real_topic = top_topics_[topic_index];

  // Compute should_be_filtered based on real topic's observing domains
  bool should_be_filtered = !IsTopicObservedByContext(
      real_topic, caller_domain, topics_data);

  // 5% of the time, replace with a random topic for plausible deniability
  if (use_random_topic) {
    Topic random_topic = GetRandomTopic();
    // BUG: should_be_filtered was computed for real_topic's domains
    // but is now applied to random_topic!
    // If caller never observed the real topic -> should_be_filtered = true
    // -> random topic is ALSO filtered -> caller gets nothing
    // This defeats the 5% noise: non-observers get 0% instead of 5%
    return TopicWithFilterStatus(random_topic, should_be_filtered);
  }

  return TopicWithFilterStatus(real_topic, should_be_filtered);
}

context:
// Topics API privacy design:
// - Each epoch, user gets top-5 interest topics from browsing
// - When a site calls document.browsingTopics(), they get 1 topic per epoch
// - 5% of the time, a RANDOM topic is returned instead (noise for deniability)
// - should_be_filtered: if the calling domain never observed the user on
//   a site related to this topic, the topic should be filtered out
//
// The bug: should_be_filtered is computed based on the REAL topic's observer
// list, then applied to the RANDOM topic. A caller who never observed the
// user's real interests will NEVER receive any topic (including the 5% noise).
// This creates a binary oracle: topics=empty means 'user has no interest
// observed by this caller', violating the noise guarantee.

